<?php

namespace App\Console\Commands;

use App\Models\Prisoner;
use Illuminate\Console\Command;
use Illuminate\Support\Facades\Artisan;

/**
 * Add political prisoners surfaced by reviewing every NPPC news article
 * published BEFORE the "Remembering Ed Mead" memorial (2023-11-26). Those
 * 47 articles are largely imported Civil Liberties Defense Center (CLDC)
 * case coverage from 2012–2023.
 *
 * Behaviour:
 *   - Creates each prisoner (with cases) via the canonical `prisoner:add`
 *     pipeline, which skips anyone already present by exact name.
 *   - For prisoners that ALREADY exist, applies the release date from the
 *     source article to their case when the case has none yet (so the
 *     "someone was released" articles update existing records too).
 *
 * Idempotent — safe to re-run.
 *
 * CAVEATS (verify before relying on specifics):
 *   - Where a field was not stated in the article it is omitted. A few
 *     well-documented facts for famous figures (Manning's 35-yr sentence
 *     and 2017 commutation; Peltier's two life terms; Stewart's 2005
 *     conviction and 2017 death; Marius Mason's ~22-yr sentence; the
 *     death/release dates for Wallace and Buck) are drawn from public
 *     record, NOT from the articles.
 *   - Disposition unverified for: Loren Reed (article predates his trial),
 *     Sam Jessup (verdict not stated), George Sexton (statute voided; no
 *     standing conviction stated), F. Emily Semple (charges dismissed).
 *   - Many entries (MN valve turners, Line 3 water protectors, Springfield
 *     BLM, Eugene cases) were CHARGED for political acts but acquitted or
 *     had charges dismissed — included as requested; `convicted` reflects
 *     that.
 */
final class AddCldcArchivePrisoners extends Command {
    protected $signature = 'prisoners:add-cldc-archive';
    protected $description = 'Add political prisoners mined from pre-2023-11-26 CLDC news coverage (idempotent; updates release dates on existing records)';

    public function handle(): int {
        $entries = json_decode($this->entriesJson(), true);
        if (! is_array($entries)) {
            $this->error('Internal error: entry JSON failed to decode.');
            return self::FAILURE;
        }

        $created = 0; $existing = 0; $releaseUpdated = 0;

        foreach ($entries as $e) {
            $name = $e['name'];
            $found = Prisoner::where('name', $name)->first();

            if ($found) {
                $existing++;
                $this->warn("Exists: {$name}");
                if ($this->applyReleaseDate($found, $e)) {
                    $releaseUpdated++;
                }
                continue;
            }

            Artisan::call('prisoner:add', [
                'json' => json_encode($e, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES),
            ]);
            $out = trim(Artisan::output());
            $this->line($out !== '' ? $out : "Added {$name}");
            $created++;
        }

        $this->info("\nDone. Created {$created}, already-present {$existing} (release date set on {$releaseUpdated}).");
        return self::SUCCESS;
    }

    /**
     * For an already-existing prisoner, copy the article's release date onto
     * a case that has none yet, and flag them released. Never overwrites an
     * existing release date. Returns true if it changed anything.
     */
    private function applyReleaseDate(Prisoner $prisoner, array $entry): bool {
        $release = $entry['cases'][0]['release_date'] ?? null;
        if (! $release) {
            return false;
        }

        // Prefer a case that has no release date recorded.
        $case = $prisoner->cases()->whereNull('release_date')->first()
            ?? $prisoner->cases()->first();

        if (! $case) {
            $this->line("  (no case on record — left unchanged)");
            return false;
        }
        if (! empty($case->release_date)) {
            $this->line("  release date already set — left unchanged");
            return false;
        }

        $case->release_date = $release;
        $case->save();
        $prisoner->released = true;
        $prisoner->in_custody = false;
        $prisoner->save();
        $this->info("  set release date {$release} on existing record");
        return true;
    }

    /** All entries as one JSON document (literal — no PHP escaping). */
    private function entriesJson(): string {
        return <<<'JSON'
[
  {"name":"Chelsea Manning","first_name":"Chelsea","last_name":"Manning","description":"U.S. Army intelligence analyst who in 2010 disclosed hundreds of thousands of classified military and State Department documents to WikiLeaks, exposing abuses during the Iraq and Afghanistan wars. Convicted under the Espionage Act in 2013 and sentenced to 35 years; her sentence was commuted by President Obama in 2017. Featured in early CLDC/NPPC coverage as a soldier facing life in prison for revealing the truth.","gender":"Female","ideologies":["Anti-war","Transparency","Whistleblower"],"era":"War on Terror","in_custody":false,"released":true,"cases":[{"institution_name":"United States Disciplinary Barracks, Fort Leavenworth","institution_state":"Kansas","charges":"Espionage Act violations; theft of government property (disclosure of classified records to WikiLeaks)","incarceration_date":"2010-05-27","release_date":"2017-05-17","sentence":"35 years (commuted by President Obama in 2017)","convicted":"Yes — court-martial, 2013"}]},
  {"name":"Leonard Peltier","first_name":"Leonard","last_name":"Peltier","description":"Longtime Native American activist and member of the American Indian Movement (AIM), convicted in 1977 for the 1975 deaths of two FBI agents at the Pine Ridge Reservation after a trial widely condemned by human-rights groups. Imprisoned for over four decades; granted home confinement in 2025. NPPC/CLDC coverage notes prosecutors later conceded they could not prove who killed the agents.","race":"Native American","gender":"Male","ideologies":["Indigenous rights","American Indian Movement"],"affiliation":["American Indian Movement"],"era":"Black liberation","in_custody":false,"released":true,"cases":[{"institution_name":"USP Coleman","institution_state":"Florida","charges":"First-degree murder of two FBI agents (Pine Ridge, 1975)","incarceration_date":"1976-02-06","sentence":"Two consecutive life terms; home confinement granted 2025","convicted":"Yes — 1977"}]},
  {"name":"Lynne Stewart","first_name":"Lynne","last_name":"Stewart","description":"Radical civil-rights and movement-defense attorney convicted in 2005 of providing material support to terrorism for relaying messages from her client to the press. Imprisoned at FMC Carswell, she waged a public fight for compassionate release while terminally ill with cancer, granted in late 2013/early 2014. She died in 2017. NPPC/CLDC coverage reproduced her appeal denouncing the Bureau of Prisons for holding political prisoners until near death.","gender":"Female","state":"New York","ideologies":["Civil rights","Movement lawyering"],"in_custody":false,"released":true,"death_date":"2017-03-07","cases":[{"institution_name":"FMC Carswell","institution_state":"Texas","charges":"Conspiracy and providing material support to terrorism (relaying client communications)","incarceration_date":"2009-11-19","release_date":"2014-01-01","sentence":"10 years (compassionate release granted Dec 2013/Jan 2014)","convicted":"Yes — 2005"}]},
  {"name":"Joseph Dibee","first_name":"Joseph","last_name":"Dibee","description":"Earth Liberation Front / Animal Liberation Front activist indicted in 2006 in the federal Operation Backfire (\"Green Scare\") roundup for a string of 1990s–2001 economic-sabotage arsons. He evaded capture for 12 years until arrested in 2018, was held in Portland, and released on conditions in January 2021. In April 2022 he pleaded guilty to three counts including conspiracy and the arson of the Cavel West horse slaughterhouse.","state":"Oregon","ideologies":["Earth Liberation Front","Animal Liberation Front","Eco-anarchism"],"affiliation":["Earth Liberation Front","Animal Liberation Front"],"era":"Green Scare","in_custody":false,"released":true,"cases":[{"institution_name":"U.S. District Court, District of Oregon","institution_state":"Oregon","charges":"Conspiracy to destroy property by fire; arson (Cavel West horse slaughterhouse); conspiracy to commit arson","arrest_date":"2018-08-09","incarceration_date":"2018-08-10","release_date":"2021-01-08","sentence":"Plea deal April 2022; advisory range 87–108 months","convicted":"Yes — guilty plea, 2022"}]},
  {"name":"Daniel McGowan","first_name":"Daniel","last_name":"McGowan","description":"Earth Liberation Front activist and Operation Backfire (\"Green Scare\") defendant who pleaded guilty to arson-related charges for two 2001 ELF actions in Oregon. A non-cooperating defendant, he served roughly seven years, much of it in a restrictive federal Communication Management Unit, and was released in December 2012. In April 2013 he was briefly re-jailed over a Huffington Post blog post under a prison regulation later found unconstitutional, then returned to his halfway house.","state":"Oregon","ideologies":["Earth Liberation Front","Eco-anarchism"],"affiliation":["Earth Liberation Front"],"era":"Green Scare","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (Communication Management Unit)","charges":"Arson and conspiracy (ELF actions, 2001)","release_date":"2012-12-11","sentence":"~7 years (released Dec 2012; sentence ended June 2013)","convicted":"Yes — guilty plea"}]},
  {"name":"Marius Mason","first_name":"Marius","last_name":"Mason","description":"Earth Liberation Front / Animal Liberation Front activist and Operation Backfire (\"Green Scare\") defendant. A non-cooperating defendant, he pleaded guilty to eco-sabotage including a 1999 arson at a Michigan State University genetic-engineering lab and received the longest sentence of any Green Scare defendant. NPPC coverage (2018) noted he was the only Green Scare defendant still imprisoned at the time of Joseph Dibee's arrest. A transgender man, his case has drawn extensive solidarity organizing.","gender":"Male","ideologies":["Earth Liberation Front","Animal Liberation Front","Eco-anarchism"],"affiliation":["Earth Liberation Front","Animal Liberation Front"],"era":"Green Scare","in_custody":true,"released":false,"cases":[{"institution_name":"Federal Bureau of Prisons","charges":"Arson and destruction of property (ELF/ALF eco-sabotage, incl. 1999 Michigan State University lab arson)","sentence":"Nearly 22 years (public record; not stated in article)","convicted":"Yes — guilty plea, 2009"}]},
  {"name":"Jonathan Paul","first_name":"Jonathan","last_name":"Paul","description":"Animal Liberation Front / Earth Liberation Front activist and Operation Backfire (\"Green Scare\") defendant. One of the non-cooperating defendants who refused to inform on co-defendants and served additional prison time for his role in 1990s–2001 eco-sabotage actions.","ideologies":["Animal Liberation Front","Earth Liberation Front","Eco-anarchism"],"affiliation":["Animal Liberation Front","Earth Liberation Front"],"era":"Green Scare","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons","charges":"Conspiracy / arson (ELF–ALF eco-sabotage)","convicted":"Yes — guilty plea"}]},
  {"name":"Joyanna Zacher","first_name":"Joyanna","last_name":"Zacher","description":"Earth Liberation Front activist and Operation Backfire (\"Green Scare\") defendant; one of the non-cooperating defendants who refused to inform on co-defendants and served additional prison time for ELF eco-sabotage in the Pacific Northwest (1996–2001).","ideologies":["Earth Liberation Front","Eco-anarchism"],"affiliation":["Earth Liberation Front"],"era":"Green Scare","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons","charges":"Conspiracy / arson (ELF eco-sabotage)","convicted":"Yes — guilty plea"}]},
  {"name":"Nathan Block","first_name":"Nathan","last_name":"Block","description":"Earth Liberation Front activist and Operation Backfire (\"Green Scare\") defendant; one of the non-cooperating defendants who refused to inform on co-defendants and served additional prison time for ELF eco-sabotage in the Pacific Northwest (1996–2001).","ideologies":["Earth Liberation Front","Eco-anarchism"],"affiliation":["Earth Liberation Front"],"era":"Green Scare","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons","charges":"Conspiracy / arson (ELF eco-sabotage)","convicted":"Yes — guilty plea"}]},
  {"name":"Rebecca Rubin","first_name":"Rebecca","last_name":"Rubin","description":"Earth Liberation Front / Animal Liberation Front activist and Operation Backfire (\"Green Scare\") defendant. After years as a fugitive she surrendered and was prosecuted; listed among the non-cooperating Green Scare defendants who served prison time for 1990s–2001 eco-sabotage actions.","gender":"Female","ideologies":["Earth Liberation Front","Animal Liberation Front","Eco-anarchism"],"affiliation":["Earth Liberation Front","Animal Liberation Front"],"era":"Green Scare","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons","charges":"Conspiracy / arson (ELF/ALF eco-sabotage)","convicted":"Yes — guilty plea"}]},
